INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-6f0ba476-moex-00022', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年初向乙公司承租一輛貨車，租期4年，每年底支付租金$100,000，並約定甲公 司可於租約期滿以$20,000購買此貨車，甲公司可以合理確定將行使此選擇權。甲公司估計該 貨車於租約期滿後可以再使用2年，無殘值，採直線法提列折舊。X1年初，甲公司為安排此 租賃而支付原始直接成本$30,000。甲公司無法得知該租賃之隱含利率，其增額借款利率為 8%。折現率8%之複利現值因子與年金現值因子如下表所示。 4年期 6年期 複利現值因子 0.7350 0.6302 年金現值因子 3.3121 4.6229 甲公司X1年之會計處理，下列何者錯誤？', '["X1年初認列租賃負債$345,910", "X1年初認列使用權資產$375,910", "X1年利息費用$27,673", "X1年折舊費用$93,978 22340"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00023', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '下列那（些）項目屬於甲公司的存貨？', '["甲公司銷售商品予乙客戶，約定起運點交貨，該批商品目前正在運送途中", "甲公司自丙供應商購入商品，約定起運點交貨，該批商品目前正在運送途中", "甲公司受丁公司委託代為銷售一批商品，該批商品目前存放於甲公司倉庫中", "甲公司銷售商品予戊客戶，雙方約定於3個月後，甲公司依原售價加計5%購回該批商品"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00024', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年1月1日以公允價值$963,550購入乙公司4年期公司債，並將之分類為按攤 銷後成本衡量之金融資產，另支付交易成本$1,800。該債券面額$1,000,000，票面利率 5%， 每年 12 月 31 日付息一次，設算市場利率為 6%。甲公司在 X2 年 9 月 30 日以公允價值 $1,023,768（含應計利息）出售該債券投資，並支付交易成本$1,850。上述交易對甲公司X2年 之綜合損益的影響為何？', '["$6,700", "$42,350", "$48,561", "$48,647"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00025', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司在X1年初以$100,000購得A設備，估計使用年限5年，殘值$2,000，採雙倍數餘額 遞減法提列折舊，並以月為計算折舊單位。X3年10月1日，甲公司以A設備交換乙公司之 B機器，並支付現金$13,000，B機器之公允價值為$40,000，且甲公司判斷該交換具商業實質。 甲公司應認列A設備之處分損益為多少？', '["$0", "利益$1,464", "利益$1,800", "利益$14,800"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00026', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司為電腦製造商，每台電腦售價$28,500，並附一年期保固維修服務。為服務客戶，甲公 司另推出二年期保固合約，單獨售價為$1,500。若客戶購買電腦時加購二年期保固合約，則除 原有一年期保固服務外，可再延長二年保固服務（共計三年保固服務），合購價$29,000。經甲 公司分析研判，一年期保固服務屬於保證型保固，平均維修成本為$1,200；二年期保固服務則 屬於勞務型保固。甲公司於X1年共出售200台電腦，其中120台電腦有加購二年期保固合 約，另外80台電腦則未加購二年期保固合約。甲公司X1年之電腦銷貨收入為多少？', '["$5,520,000", "$5,586,000", "$5,760,000", "$5,880,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00027', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', 'X1年底，甲公司有存貨：製成品1,500件，每件成本$40；原料1,000件，每件成本$25，每 件原料需再投入加工成本$17才能成為製成品。銷售費用為每件$2，正常售價為每件$43。甲 公司與乙客戶在X1年9月簽訂不可撤銷合約，將於X2年1月以每件$45銷售1,200件製成 品予乙客戶。甲公司X1年期末存貨之淨變現價值為多少？', '["製成品$60,000，原料$25,000", "製成品$61,500，原料$26,000", "製成品$63,900，原料$24,000", "製成品$66,900，原料$23,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00028', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司會計人員估算 X1 年可售商品零售價為$560,000，並以加權平均零售價法計算成本比 率為70%，且依此估算期末存貨成本為$52,500。然經再次檢視相關資料發現估算期末存貨成 本時忽略 X1 年曾將一批商品退回給供應商，該批商品成本為$5,660，零售價為$12,000；另 有員工折扣$5,000亦被忽略。經修正後，甲公司估算X1年期末存貨成本應為多少？', '["$40,890", "$44,415", "$47,940", "$57,007"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00029', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'essay', '甲將其所有之 A屋出租予乙經營托嬰中心，租期五年。詎料在租賃存續
期間，乙僱用之托育人員丙過失疏於照顧入睡中之嬰兒丁，造成丁於 A
屋窒息死亡，致甲所有之 A屋價值減損新臺幣（下同）300萬元。試問：
甲依民法第 432條、第 433條請求乙賠償該 300萬元之損害，是否有理
由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0905", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00030', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'essay', '甲有名牌女鑽錶 A 一只，甲於民國（下同）113 年 12 月 31 日參加跨年
晚會時，不慎遺失 A 錶，當晚為乙所拾獲。乙為取悅其女友丙，114 年
3 月 1 日於丙生日之際，將 A錶贈與並交付給善意且無重大過失不知之
丙。同年 6 月 1日甲向丙請求返還 A鑽錶，丙則以善意且無重大過失不
知為由，拒絕返還。試問：
乙、丙贈與契約之效力如何？（10分）
甲以所有物返還請求權向丙主張返還 A錶，是否有理由？（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0905", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00031', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲與乙為同一棟社區之住戶，甲住8樓，乙住7樓，甲生性愛熱鬧，常常邀約親朋好友到家作客， 並大聲喧嘩，甚至已半夜時分仍在家中高歌作樂。下列敘述，何者錯誤？', '["在他人居住區域，發出超越一般人社會生活所能忍受之噪音，屬不法侵害他人居住安寧之人格 利益", "人格利益至高無上，不容侵犯，只要遭受侵害，不問程度如何，被害人均得依民法第195條第 1項有關人格及身分法益侵害規定，請求賠償相當之金額", "如果長期、持續性噪音，已使人因此無法入眠，健康受損，可能構成健康權之侵害", "健康權屬於特別人格權，若受侵害，被害人得請求非財產上之金錢賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL)
